from flask import Flask, request, jsonify, url_for
from flask_mail import Mail, Message
import uuid

app = Flask(__name__)
app.config['MAIL_SERVER'] = 'smtp.example.com'
app.config['MAIL_PORT'] = 465
app.config['MAIL_USERNAME'] = 'your_email@example.com'
app.config['MAIL_PASSWORD'] = 'your_password'
app.config['MAIL_USE_TLS'] = False
app.config['MAIL_USE_SSL'] = True
mail = Mail(app)

# In-memory user store for demonstration purposes
users = {
    'user@example.com': {'mfa_enabled': True, 'mfa_secret': 'some_secret'}
}

@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    email = request.json.get('email')
    if email in users:
        users[email]['mfa_enabled'] = True
        return jsonify({"message": "MFA enabled"}), 200
    return jsonify({"message": "User not found"}), 404

@app.route('/disable-mfa', methods=['POST'])
def disable_mfa():
    email = request.json.get('email')
    if email in users:
        users[email]['mfa_enabled'] = False
        return jsonify({"message": "MFA disabled"}), 200
    return jsonify({"message": "User not found"}), 404

@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    email = request.json.get('email')
    if email in users:
        token = str(uuid.uuid4())
        reset_link = url_for('confirm_reset', token=token, _external=True)
        msg = Message('Reset MFA', sender='your_email@example.com', recipients=[email])
        msg.body = f'Click the link to reset your MFA: {reset_link}'
        mail.send(msg)
        return jsonify({"message": "Reset link sent to your email"}), 200
    return jsonify({"message": "User not found"}), 404

@app.route('/confirm-reset/<token>', methods=['GET'])
def confirm_reset(token):
    # Token validation logic should be implemented here
    for email, data in users.items():
        if data.get('token') == token:  # Example; should secure token validation 
            users[email]['mfa_enabled'] = False
            return jsonify({"message": "MFA has been disabled"}), 200
    return jsonify({"message": "Invalid or expired token"}), 404

if __name__ == '__main__':
    app.run(debug=True)